// Gather profile data and CV data
const profileRows = $('Load LinkedIn Profile').all().map(i => i.json);
const cvRows = $('Load Recent CVs').all().map(i => i.json);

// Build profile object from sections
const profile = {};
for (const row of profileRows) {
  if (!profile[row.profile_section] || row.version > (profile[row.profile_section].version || 0)) {
    profile[row.profile_section] = {
      data: row.section_data,
      version: row.version,
      last_updated: row.last_updated
    };
  }
}

const hasProfile = Object.keys(profile).length > 0;
const hasCVs = cvRows.length > 0 && cvRows[0].cv_identifier !== 'latest_cv';

// If no profile data, skip comparison
if (!hasProfile) {
  return [{
    json: {
      skip: true,
      reason: 'No LinkedIn profile data found. Please add profile data via the manual ingestion webhook first.',
      profile: {},
      cvs: []
    }
  }];
}

return [{
  json: {
    skip: false,
    profile: profile,
    cvs: cvRows,
    profile_sections: Object.keys(profile)
  }
}];

// Parse Claude's analysis
const response = $json;
let content = '';
if (response.content && response.content[0]) {
  content = response.content[0].text;
}

let analysis = {};
try {
  const match = content.match(/\{[\s\S]*\}/);
  if (match) {
    analysis = JSON.parse(match[0]);
  }
} catch (e) {
  analysis = {
    discrepancies: [],
    overall_status: 'aligned',
    analysis: 'Could not parse alignment analysis. Manual review recommended.',
    resolution_recommendations: ['Run alignment check manually']
  };
}

const discrepancies = analysis.discrepancies || [];
const criticalCount = discrepancies.filter(d => d.severity === 'critical').length;
const warningCount = discrepancies.filter(d => d.severity === 'warning').length;
const infoCount = discrepancies.filter(d => d.severity === 'info').length;

// Get CV info from upstream
const checkData = $('Check Data Available').first().json;
const cvIdentifier = (checkData.cvs && checkData.cvs[0]) ? checkData.cvs[0].cv_identifier : 'weekly_check';
const cvTargetRole = (checkData.cvs && checkData.cvs[0]) ? checkData.cvs[0].cv_target_role : 'general';

return [{
  json: {
    cv_identifier: cvIdentifier,
    cv_target_role: cvTargetRole,
    discrepancies: JSON.stringify(discrepancies),
    critical_count: criticalCount,
    warning_count: warningCount,
    info_count: infoCount,
    overall_status: analysis.overall_status || 'aligned',
    ai_analysis: analysis.analysis || '',
    resolution_recommendations: JSON.stringify(analysis.resolution_recommendations || []),
    has_critical: criticalCount > 0,
    has_issues: criticalCount > 0 || warningCount > 0
  }
}];

const r = $('Parse Results').first().json;

const isCritical = r.critical_count > 0;
const urgency = isCritical ? 'URGENT' : 'Notice';
const color = isCritical ? '#e74c3c' : '#f39c12';

let discrepancies = [];
try { discrepancies = JSON.parse(r.discrepancies); } catch(e) {}
let recommendations = [];
try { recommendations = JSON.parse(r.resolution_recommendations); } catch(e) {}

let h = '<div style="font-family:Georgia,serif;max-width:600px;margin:0 auto;color:#333;">';
h += '<div style="background:' + color + ';color:white;padding:15px;border-radius:4px 4px 0 0;">';
h += '<h1 style="margin:0;font-size:20px;">' + urgency + ': Profile-CV Alignment Issue</h1>';
h += '<p style="margin:5px 0 0 0;font-size:14px;">CV: ' + (r.cv_target_role || r.cv_identifier) + '</p></div>';

h += '<div style="padding:15px;border:1px solid #ddd;border-top:0;">';
h += '<p><strong>Status:</strong> ' + r.overall_status.replace(/_/g, ' ') + '</p>';
h += '<p><strong>Analysis:</strong> ' + (r.ai_analysis || 'No analysis available') + '</p>';

h += '<p><strong>Issues found:</strong> ' + r.critical_count + ' critical, ' + r.warning_count + ' warnings, ' + r.info_count + ' info</p>';

if (discrepancies.length > 0) {
  h += '<h3 style="color:#1a5276;">Discrepancies</h3>';
  for (const d of discrepancies) {
    const dColor = d.severity === 'critical' ? '#e74c3c' : d.severity === 'warning' ? '#f39c12' : '#3498db';
    h += '<div style="border-left:3px solid ' + dColor + ';padding:8px;margin:8px 0;background:#f9f9f9;">';
    h += '<strong style="text-transform:uppercase;font-size:11px;color:' + dColor + ';">' + d.severity + '</strong> ';
    h += '<strong>' + (d.field || 'Unknown field') + '</strong>';
    if (d.linkedin_value) h += '<p style="margin:4px 0;font-size:13px;">LinkedIn: ' + d.linkedin_value + '</p>';
    if (d.cv_value) h += '<p style="margin:4px 0;font-size:13px;">CV: ' + d.cv_value + '</p>';
    if (d.recommendation) h += '<p style="margin:4px 0;font-size:13px;color:#555;">Fix: ' + d.recommendation + '</p>';
    h += '</div>';
  }
}

if (recommendations.length > 0) {
  h += '<h3 style="color:#1a5276;">Recommended Actions</h3><ol>';
  for (const rec of recommendations) { h += '<li style="margin:5px 0;">' + rec + '</li>'; }
  h += '</ol>';
}

h += '</div></div>';

const subject = urgency + ': Profile-CV discrepancy' + (r.cv_target_role ? ' for ' + r.cv_target_role : '');

return [{ json: { subject, html: h } }];

